import {Socket, Server} from 'net'
export interface SetProxyServerOptions {
  address: string
  port: number
  shouldUseProxy?: (data: {
    socket: Socket
    destinationInfo: AddressInfo
    originInfo: AddressInfo
  }) => boolean
}

export interface ProxyServers {
  shouldUseProxy?: (data: {
    socket: Socket
    destinationInfo: AddressInfo
    originInfo: AddressInfo
  }) => boolean
  getAvailableProxy: () => SingleProxyOptions
}

export interface ISocksServer {
  server: Server
  on: (event: string, listener: (...args: any[]) => void) => void
  listen: (...args: any[]) => void
  listenAsync: (port: number, host?: string) => void
  close: (...args: any[]) => void
  getConnections: (cb: (error: Error | null, count: number) => void) => void

  // SERVER-SIDE upstream-SOCKS5 chain (tunnel load-balancing in eg-chromedriver-image).
  setProxyServer: (proxyServer: SetProxyServerOptions) => void
  setProxyServers: (proxyServers: ProxyServers) => void
  getProxyServers: () => ProxyServers | undefined

  // CLIENT-SIDE upstream HTTP-CONNECT proxy (tunnel agent reaching AUT through a
  // customer's corporate proxy). Distinct from setProxyServer(s) — see
  // ./execute-request-through-http-proxy.d.ts for the resolver contract.
  setHttpProxyResolver: (resolver: HttpProxyResolver) => void
}

import * as Commons from './utils'
import {AddressInfo, SingleProxyOptions} from './utils'
import {HttpProxyResolver} from './execute-request-through-http-proxy'

export type Socks5ProxyOptions = Commons.Socks5ProxyOptions
